// Layout IR types for pretext-md
// These types bridge the gap between mdast (remark's AST) and pretext measurement.

// --- Font configuration ---

export type FontConfig = {
  body: string       // e.g. '14px "Inter", sans-serif'
  bold: string       // e.g. 'bold 14px "Inter", sans-serif'
  italic: string     // e.g. 'italic 14px "Inter", sans-serif'
  boldItalic: string // e.g. 'bold italic 14px "Inter", sans-serif'
  code: string       // e.g. '13px "Fira Code", monospace'
  h1: string
  h2: string
  h3: string
  h4: string
  h5: string
  h6: string
}

export type LineHeightConfig = {
  body: number    // e.g. 20
  code: number    // e.g. 18
  h1: number      // e.g. 32
  h2: number      // e.g. 28
  h3: number      // e.g. 24
  h4: number
  h5: number
  h6: number
}

export type MeasureConfig = {
  maxWidth: number
  fonts: FontConfig
  lineHeights: LineHeightConfig
  plugins?: EmbedPlugin[]
}

// --- Block-level nodes (parser output) ---

export type BlockNode =
  | ParagraphNode
  | HeadingNode
  | CodeBlockNode
  | BlockquoteNode
  | ListNode
  | ThematicBreakNode
  | ImageNode
  | TableNode

export type ParagraphNode = {
  kind: 'paragraph'
  items: InlineItem[]
}

export type HeadingNode = {
  kind: 'heading'
  level: 1 | 2 | 3 | 4 | 5 | 6
  items: InlineItem[]
}

export type CodeBlockNode = {
  kind: 'code-block'
  lang: string
  code: string
  meta?: string
}

export type BlockquoteNode = {
  kind: 'blockquote'
  children: BlockNode[]
}

export type ListNode = {
  kind: 'list'
  ordered: boolean
  start?: number
  items: BlockNode[][]
}

export type ThematicBreakNode = {
  kind: 'hr'
}

export type ImageNode = {
  kind: 'image'
  src: string
  alt?: string
}

export type TableAlignType = 'left' | 'center' | 'right' | null

export type TableNode = {
  kind: 'table'
  align: TableAlignType[]
  rows: InlineItem[][][] // rows → cells → inline items
}

// --- Inline items (within paragraphs/headings) ---

export type InlineItem =
  | TextItem
  | CodeItem
  | LinkItem
  | BreakItem

export type TextItem = {
  kind: 'text'
  text: string
  font: FontStyle
}

export type CodeItem = {
  kind: 'code'
  text: string
}

export type LinkItem = {
  kind: 'link'
  items: InlineItem[]
  href: string
}

export type BreakItem = {
  kind: 'break'
}

// font style resolved during inline layout based on FontConfig
export type FontStyle = 'body' | 'bold' | 'italic' | 'boldItalic' | 'strikethrough'

// --- Measured output ---

export type MeasuredBlock = {
  node: BlockNode
  height: number
  y: number
  lines?: MeasuredLine[]          // for paragraph/heading/code blocks
  children?: MeasuredBlock[]      // for blockquote inner blocks
  items?: MeasuredBlock[][]       // for list items (each item = array of measured blocks)
}

export type MeasuredLine = {
  fragments: LineFragment[]
  width: number
  y: number // offset within block
}

export type LineFragment = {
  text: string
  width: number
  font: string      // resolved CSS font string
  fontStyle: FontStyle
  leadingGap: number // marginLeft gap before this fragment
  href?: string
  isCode?: boolean
  isStrikethrough?: boolean
}

export type MeasureResult = {
  height: number
  lineCount: number
  blocks: MeasuredBlock[]
}

// --- Plugin system ---

export type EmbedMeasurement =
  | { kind: 'fixed'; height: number }
  | { kind: 'computed'; height: number }
  | { kind: 'aspect-ratio'; ratio: number; maxHeight?: number }

/** Context passed to plugins for recursive measurement. */
export type PluginContext = {
  measureBlocks: (blocks: BlockNode[], config: MeasureConfig) => MeasureResult
  config: MeasureConfig
}

export type EmbedPlugin = {
  name: string
  match: (node: BlockNode) => boolean
  /** Simple measurement — returns a height. For leaf blocks (code, image, hr). */
  measure: (node: any, maxWidth: number, ctx?: PluginContext) => EmbedMeasurement
  /** Full measurement — returns MeasuredBlock with children/lines. For container blocks (blockquote, list). */
  measureBlock?: (node: any, ctx: PluginContext) => MeasuredBlock
}

// mdast walker — converts remark AST to our layout IR (BlockNode/InlineItem)

import { unified } from 'unified'
import remarkParse from 'remark-parse'
import remarkGfm from 'remark-gfm'
import type {
  BlockNode,
  InlineItem,
  FontStyle,
} from './types'
import type {
  Root,
  Content,
  PhrasingContent,
  Paragraph,
  Heading,
  Code,
  Blockquote,
  List,
  ListItem,
  ThematicBreak,
  Text,
  Emphasis,
  Strong,
  InlineCode,
  Link,
  Delete,
  Break,
  Image,
  Table,
  TableRow,
  TableCell,
  AlignType,
} from 'mdast'

const parser = unified().use(remarkParse).use(remarkGfm)

export function parse(markdown: string): BlockNode[] {
  // Strip HTML comments before parsing (same as MarkdownRenderer)
  const cleaned = markdown.replace(/<!--[\s\S]*?-->/g, '')
  const tree = parser.parse(cleaned) as Root
  return walkBlocks(tree.children)
}

function walkBlocks(nodes: Content[]): BlockNode[] {
  const blocks: BlockNode[] = []
  for (const node of nodes) {
    const block = walkBlock(node)
    if (block) blocks.push(block)
  }
  return blocks
}

function walkBlock(node: Content): BlockNode | null {
  switch (node.type) {
    case 'paragraph':
      return walkParagraph(node as Paragraph)
    case 'heading':
      return walkHeading(node as Heading)
    case 'code':
      return walkCode(node as Code)
    case 'blockquote':
      return walkBlockquote(node as Blockquote)
    case 'list':
      return walkList(node as List)
    case 'thematicBreak':
      return { kind: 'hr' } as const
    case 'table':
      return walkTable(node as Table)
    default:
      return null
  }
}

function walkParagraph(node: Paragraph): BlockNode {
  // Image-only paragraph → promote to block-level image
  if (node.children.length === 1 && node.children[0]!.type === 'image') {
    const img = node.children[0] as Image
    return { kind: 'image', src: img.url, alt: img.alt ?? undefined }
  }
  return {
    kind: 'paragraph',
    items: walkInlines(node.children, 'body'),
  }
}

function walkHeading(node: Heading): BlockNode {
  return {
    kind: 'heading',
    level: node.depth as 1 | 2 | 3 | 4 | 5 | 6,
    items: walkInlines(node.children, 'body'),
  }
}

function walkCode(node: Code): BlockNode {
  return {
    kind: 'code-block',
    lang: node.lang ?? '',
    code: node.value,
    meta: node.meta ?? undefined,
  }
}

function walkBlockquote(node: Blockquote): BlockNode {
  return {
    kind: 'blockquote',
    children: walkBlocks(node.children),
  }
}

function walkList(node: List): BlockNode {
  return {
    kind: 'list',
    ordered: node.ordered ?? false,
    start: node.start ?? undefined,
    items: node.children.map((item: ListItem) => walkBlocks(item.children)),
  }
}

function walkTable(node: Table): BlockNode {
  const align = (node.align ?? []).map((a: AlignType | null | undefined) =>
    a === 'left' || a === 'center' || a === 'right' ? a : null,
  )
  const rows = node.children.map((row: TableRow) =>
    row.children.map((cell: TableCell) =>
      walkInlines(cell.children as PhrasingContent[], 'body'),
    ),
  )
  return { kind: 'table', align, rows }
}

// --- Inline walking ---

function walkInlines(nodes: PhrasingContent[], fontStyle: FontStyle): InlineItem[] {
  const items: InlineItem[] = []
  for (const node of nodes) {
    walkInline(node, fontStyle, items)
  }
  return items
}

function walkInline(node: PhrasingContent, fontStyle: FontStyle, out: InlineItem[]): void {
  switch (node.type) {
    case 'text':
      out.push({ kind: 'text', text: (node as Text).value, font: fontStyle })
      break
    case 'strong':
      walkInlineChildren((node as Strong).children, applyBold(fontStyle), out)
      break
    case 'emphasis':
      walkInlineChildren((node as Emphasis).children, applyItalic(fontStyle), out)
      break
    case 'delete':
      walkInlineChildren((node as Delete).children, 'strikethrough', out)
      break
    case 'inlineCode':
      out.push({ kind: 'code', text: (node as InlineCode).value })
      break
    case 'link':
      out.push({
        kind: 'link',
        href: (node as Link).url,
        items: walkInlines((node as Link).children, fontStyle),
      })
      break
    case 'break':
      out.push({ kind: 'break' })
      break
    default:
      // skip unknown inline nodes
      break
  }
}

function walkInlineChildren(nodes: PhrasingContent[], fontStyle: FontStyle, out: InlineItem[]): void {
  for (const node of nodes) {
    walkInline(node, fontStyle, out)
  }
}

function applyBold(current: FontStyle): FontStyle {
  if (current === 'italic' || current === 'boldItalic') return 'boldItalic'
  return 'bold'
}

function applyItalic(current: FontStyle): FontStyle {
  if (current === 'bold' || current === 'boldItalic') return 'boldItalic'
  return 'italic'
}

// Mixed-font inline layout engine
//
// Based on chenglou's rich-note demo pattern:
// - Flatten inline items to prepared runs
// - Layout lines greedily with layoutNextLine per run
// - Use leadingGap (marginLeft) for inter-fragment spacing instead of absolute x
// - Trim text, convert boundary whitespace to measured gaps

import {
  prepareWithSegments,
  layoutNextLine,
  walkLineRanges,
  type PreparedTextWithSegments,
  type LayoutCursor,
} from '@chenglou/pretext'
import type {
  InlineItem,
  FontConfig,
  FontStyle,
  MeasuredLine,
  LineFragment,
} from './types'

// --- Internal types ---

type PreparedTextItem = {
  kind: 'text'
  font: string
  fontStyle: FontStyle
  chromeWidth: number
  endCursor: LayoutCursor
  fullText: string
  fullWidth: number
  leadingGap: number
  prepared: PreparedTextWithSegments
  href?: string
  isCode?: boolean
  isStrikethrough?: boolean
}

type PreparedBreakItem = {
  kind: 'break'
}

type PreparedItem = PreparedTextItem | PreparedBreakItem

// --- Constants ---

const LINE_START: LayoutCursor = { segmentIndex: 0, graphemeIndex: 0 }
const UNBOUNDED = 100_000
const CODE_CHROME_WIDTH = 8 // 4px padding each side

// --- Measurement helpers ---

const collapsedSpaceWidthCache = new Map<string, number>()

function measureSingleLineWidth(prepared: PreparedTextWithSegments): number {
  let maxWidth = 0
  walkLineRanges(prepared, UNBOUNDED, line => {
    if (line.width > maxWidth) maxWidth = line.width
  })
  return maxWidth
}

function getCollapsedSpaceWidth(font: string): number {
  const cached = collapsedSpaceWidthCache.get(font)
  if (cached !== undefined) return cached
  const joined = measureSingleLineWidth(prepareWithSegments('A A', font))
  const compact = measureSingleLineWidth(prepareWithSegments('AA', font))
  const w = Math.max(0, joined - compact)
  collapsedSpaceWidthCache.set(font, w)
  return w
}

// Resolve FontStyle to CSS font string
function resolveFont(style: FontStyle, fonts: FontConfig): string {
  switch (style) {
    case 'body': return fonts.body
    case 'bold': return fonts.bold
    case 'italic': return fonts.italic
    case 'boldItalic': return fonts.boldItalic
    case 'strikethrough': return fonts.body
  }
}

// --- Flatten + prepare ---
// Two-pass: first flatten the inline tree to raw runs (preserving gap state
// across link boundaries), then prepare each run with pretext.

type RawRun =
  | { kind: 'text'; text: string; font: string; fontStyle: FontStyle; href?: string; isCode?: boolean; isStrikethrough?: boolean; chromeWidth: number }
  | { kind: 'break' }

function flattenRuns(items: InlineItem[], fonts: FontConfig, out: RawRun[], parentHref?: string): void {
  for (const item of items) {
    switch (item.kind) {
      case 'text':
        out.push({
          kind: 'text',
          text: item.text,
          font: resolveFont(item.font, fonts),
          fontStyle: item.font,
          href: parentHref,
          isStrikethrough: item.font === 'strikethrough',
          chromeWidth: 0,
        })
        break
      case 'code':
        out.push({
          kind: 'text',
          text: item.text,
          font: fonts.code,
          fontStyle: 'body',
          href: parentHref,
          isCode: true,
          chromeWidth: CODE_CHROME_WIDTH,
        })
        break
      case 'link':
        flattenRuns(item.items, fonts, out, item.href)
        break
      case 'break':
        out.push({ kind: 'break' })
        break
    }
  }
}

function prepareRuns(runs: RawRun[]): PreparedItem[] {
  const out: PreparedItem[] = []
  let pendingGap = 0

  for (const run of runs) {
    if (run.kind === 'break') {
      out.push({ kind: 'break' })
      pendingGap = 0
      continue
    }

    const hasLeading = /^\s/.test(run.text)
    const hasTrailing = /\s$/.test(run.text)
    const trimmed = run.text.trim()
    const carryGap = pendingGap
    pendingGap = hasTrailing ? getCollapsedSpaceWidth(run.font) : 0
    if (trimmed.length === 0) continue

    const prepared = prepareWithSegments(trimmed, run.font)
    const wholeLine = layoutNextLine(prepared, LINE_START, UNBOUNDED)
    if (wholeLine === null) continue

    out.push({
      kind: 'text',
      font: run.font,
      fontStyle: run.fontStyle,
      chromeWidth: run.chromeWidth,
      endCursor: wholeLine.end,
      fullText: wholeLine.text,
      fullWidth: wholeLine.width,
      leadingGap: carryGap > 0 || hasLeading ? getCollapsedSpaceWidth(run.font) : 0,
      prepared,
      href: run.href,
      isCode: run.isCode,
      isStrikethrough: run.isStrikethrough,
    })
  }

  return out
}

function flattenAndPrepare(items: InlineItem[], fonts: FontConfig): PreparedItem[] {
  const runs: RawRun[] = []
  flattenRuns(items, fonts, runs)
  return prepareRuns(runs)
}

// --- Cursor helpers ---

function cursorsMatch(a: LayoutCursor, b: LayoutCursor): boolean {
  return a.segmentIndex === b.segmentIndex && a.graphemeIndex === b.graphemeIndex
}

// --- Line layout ---

export function layoutInline(
  items: InlineItem[],
  maxWidth: number,
  fonts: FontConfig,
  lineHeight: number,
): MeasuredLine[] {
  const prepared = flattenAndPrepare(items, fonts)
  if (prepared.length === 0) return []

  const lines = layoutPreparedItems(prepared, maxWidth)
  return lines.map((line, i) => ({
    fragments: line.fragments,
    width: line.width,
    y: i * lineHeight,
  }))
}

type RawLine = {
  fragments: LineFragment[]
  width: number
}

function layoutPreparedItems(items: PreparedItem[], maxWidth: number): RawLine[] {
  const lines: RawLine[] = []
  const safeWidth = Math.max(1, maxWidth)

  let itemIndex = 0
  let textCursor: LayoutCursor | null = null

  while (itemIndex < items.length) {
    const item = items[itemIndex]!

    // Handle hard breaks
    if (item.kind === 'break') {
      lines.push({ fragments: [], width: 0 })
      itemIndex++
      textCursor = null
      continue
    }

    const fragments: LineFragment[] = []
    let lineWidth = 0
    let remainingWidth = safeWidth

    lineLoop:
    while (itemIndex < items.length) {
      const item = items[itemIndex]!
      if (item.kind === 'break') break lineLoop

      // Skip exhausted items
      if (textCursor !== null && cursorsMatch(textCursor, item.endCursor)) {
        itemIndex++
        textCursor = null
        continue
      }

      const leadingGap = fragments.length === 0 ? 0 : item.leadingGap
      const reservedWidth = leadingGap + item.chromeWidth

      // Can't even fit the chrome on this line
      if (fragments.length > 0 && reservedWidth >= remainingWidth) break lineLoop

      // Fast path: entire item fits on this line
      if (textCursor === null) {
        const fullWidth = leadingGap + item.fullWidth + item.chromeWidth
        if (fullWidth <= remainingWidth) {
          fragments.push({
            text: item.fullText,
            width: item.fullWidth + item.chromeWidth,
            font: item.font,
            fontStyle: item.fontStyle,
            href: item.href,
            isCode: item.isCode,
            isStrikethrough: item.isStrikethrough,
            leadingGap,
          })
          lineWidth += fullWidth
          remainingWidth = Math.max(0, safeWidth - lineWidth)
          itemIndex++
          continue
        }
      }

      // Slow path: need to break this item
      const startCursor = textCursor ?? LINE_START
      const availableWidth = Math.max(1, remainingWidth - reservedWidth)
      const line = layoutNextLine(item.prepared, startCursor, availableWidth)

      if (line === null) {
        itemIndex++
        textCursor = null
        continue
      }
      if (cursorsMatch(startCursor, line.end)) {
        if (fragments.length > 0) break lineLoop
        itemIndex++
        textCursor = null
        continue
      }

      // Guard against character-level word breaking only.
      // graphemeIndex > 0 means pretext broke mid-word (character level).
      // graphemeIndex === 0 means it broke at a word/segment boundary — that's fine.
      if (fragments.length > 0 && line.end.graphemeIndex > 0) {
        const fullLine = layoutNextLine(item.prepared, startCursor, safeWidth - item.chromeWidth)
        if (fullLine && !cursorsMatch(line.end, fullLine.end)) {
          break lineLoop
        }
      }

      fragments.push({
        text: line.text,
        width: line.width + item.chromeWidth,
        font: item.font,
        fontStyle: item.fontStyle,
        href: item.href,
        isCode: item.isCode,
        isStrikethrough: item.isStrikethrough,
        leadingGap,
      })
      lineWidth += leadingGap + line.width + item.chromeWidth
      remainingWidth = Math.max(0, safeWidth - lineWidth)

      if (cursorsMatch(line.end, item.endCursor)) {
        // Item fully consumed
        itemIndex++
        textCursor = null
        continue
      }

      // Item continues on next line
      textCursor = line.end
      break lineLoop
    }

    if (fragments.length === 0) break
    lines.push({ fragments, width: lineWidth })
  }

  return lines
}

/**
 * Quick line count — same algorithm, no fragment allocation.
 */
export function countInlineLines(
  items: InlineItem[],
  maxWidth: number,
  fonts: FontConfig,
): number {
  const prepared = flattenAndPrepare(items, fonts)
  if (prepared.length === 0) return 0
  return layoutPreparedItems(prepared, maxWidth).length
}

// Block layout coordinator
//
// Stacks blocks vertically, delegates inline measurement to the inline layout engine.
// Block types like code-block, image, hr are measured by plugins — the coordinator
// only handles paragraph, heading, list, blockquote natively.

import { layoutInline } from './inline-layout'
import type {
  BlockNode,
  MeasuredBlock,
  MeasuredLine,
  MeasureConfig,
  MeasureResult,
  FontConfig,
  LineHeightConfig,
  HeadingNode,
  EmbedPlugin,
  EmbedMeasurement,
  PluginContext,
} from './types'

// Core layout constant — the coordinator owns block spacing
const BLOCK_GAP = 12


function getHeadingFont(level: HeadingNode['level']): keyof FontConfig {
  return `h${level}` as keyof FontConfig
}

function getHeadingLineHeight(level: HeadingNode['level'], lineHeights: LineHeightConfig): number {
  return lineHeights[`h${level}` as keyof LineHeightConfig]
}

function resolveEmbedHeight(m: EmbedMeasurement, maxWidth: number): number {
  switch (m.kind) {
    case 'fixed':
    case 'computed':
      return m.height
    case 'aspect-ratio': {
      const h = maxWidth / m.ratio
      return m.maxHeight ? Math.min(h, m.maxHeight) : h
    }
  }
}

function findPlugin(block: BlockNode, plugins?: EmbedPlugin[]): EmbedPlugin | null {
  if (!plugins) return null
  for (const p of plugins) {
    if (p.match(block)) return p
  }
  return null
}

/**
 * Measure all blocks and return exact heights, y-offsets, and line data.
 */
export function measureBlocks(
  blocks: BlockNode[],
  config: MeasureConfig,
): MeasureResult {
  const measured: MeasuredBlock[] = []
  let y = 0

  for (let i = 0; i < blocks.length; i++) {
    const block = blocks[i]!
    const mb = measureBlock(block, config)
    mb.y = y
    measured.push(mb)
    y += mb.height
    if (i < blocks.length - 1) y += BLOCK_GAP
  }

  const totalLines = measured.reduce((sum, b) => sum + (b.lines?.length ?? 0), 0)

  return {
    height: y,
    lineCount: totalLines,
    blocks: measured,
  }
}

function measureBlock(block: BlockNode, config: MeasureConfig): MeasuredBlock {
  const ctx: PluginContext = { measureBlocks, config }

  // Plugins handle all non-inline block types
  const plugin = findPlugin(block, config.plugins)
  if (plugin) {
    // Full measurement: plugin returns MeasuredBlock with children/lines
    if (plugin.measureBlock) {
      return plugin.measureBlock(block, ctx)
    }
    // Simple measurement: plugin returns height
    const m = plugin.measure(block as any, config.maxWidth, ctx)
    return { node: block, height: resolveEmbedHeight(m, config.maxWidth), y: 0 }
  }

  // Core handles inline block types natively (paragraphs, headings)
  switch (block.kind) {
    case 'paragraph':
      return measureParagraph(block, config)
    case 'heading':
      return measureHeading(block, config)
    default:
      // Unknown block without plugin — rough fallback
      return { node: block, height: 40, y: 0 }
  }
}

function measureParagraph(block: BlockNode & { kind: 'paragraph' }, config: MeasureConfig): MeasuredBlock {
  const lines = layoutInline(
    block.items,
    config.maxWidth,
    config.fonts,
    config.lineHeights.body,
  )
  const height = lines.length * config.lineHeights.body
  return { node: block, height, y: 0, lines }
}

function measureHeading(block: HeadingNode, config: MeasureConfig): MeasuredBlock {
  const lineHeight = getHeadingLineHeight(block.level, config.lineHeights)
  const headingFonts: FontConfig = {
    ...config.fonts,
    body: config.fonts[getHeadingFont(block.level)],
    bold: config.fonts[getHeadingFont(block.level)],
  }
  const lines = layoutInline(
    block.items,
    config.maxWidth,
    headingFonts,
    lineHeight,
  )
  const height = lines.length * lineHeight
  return { node: block, height, y: 0, lines }
}

// Shrinkwrap — binary search for the tightest width that preserves total height.

import { parse } from './parser'
import { measureBlocks } from './block-layout'
import type { MeasureConfig, MeasureResult } from './types'

export type ShrinkwrapResult = {
  width: number
  height: number
}

/**
 * Find the tightest width that preserves the same total height.
 * Binary search on width, measuring at each candidate.
 */
export function shrinkwrap(
  markdown: string,
  config: MeasureConfig,
): ShrinkwrapResult {
  const blocks = parse(markdown)
  const initial = measureBlocks(blocks, config)

  if (initial.lineCount <= 1) {
    const maxFragWidth = getMaxContentWidth(initial)
    return { width: maxFragWidth, height: initial.height }
  }

  // Reuse a single config object, mutating maxWidth per iteration
  const searchConfig = { ...config }
  let lo = 1
  let hi = Math.ceil(config.maxWidth)
  let lastHeight = initial.height

  while (lo < hi) {
    const mid = (lo + hi) >>> 1
    searchConfig.maxWidth = mid
    const candidate = measureBlocks(blocks, searchConfig)
    if (candidate.height <= initial.height) {
      hi = mid
      lastHeight = candidate.height
    } else {
      lo = mid + 1
    }
  }

  return { width: lo, height: lastHeight }
}

function getMaxContentWidth(result: MeasureResult): number {
  let max = 0
  for (const block of result.blocks) {
    if (block.lines) {
      for (const line of block.lines) {
        max = Math.max(max, line.width)
      }
    }
  }
  return Math.ceil(max)
}

'use client'

import { createContext, useContext } from 'react'
import type { FontConfig, LineHeightConfig } from '../core/types'

export type PretextMdConfig = {
  fonts: FontConfig
  lineHeights: LineHeightConfig
}

const defaultFonts: FontConfig = {
  body: '14px "DM Sans", sans-serif',
  bold: 'bold 14px "DM Sans", sans-serif',
  italic: 'italic 14px "DM Sans", sans-serif',
  boldItalic: 'bold italic 14px "DM Sans", sans-serif',
  code: '13px "DM Mono", "Fira Code", monospace',
  h1: 'bold 24px "DM Sans", sans-serif',
  h2: 'bold 20px "DM Sans", sans-serif',
  h3: 'bold 16px "DM Sans", sans-serif',
  h4: 'bold 14px "DM Sans", sans-serif',
  h5: 'bold 13px "DM Sans", sans-serif',
  h6: 'bold 12px "DM Sans", sans-serif',
}

const defaultLineHeights: LineHeightConfig = {
  body: 20,
  code: 18,
  h1: 32,
  h2: 28,
  h3: 24,
  h4: 20,
  h5: 20,
  h6: 18,
}

export const defaultConfig: PretextMdConfig = {
  fonts: defaultFonts,
  lineHeights: defaultLineHeights,
}

export const PretextMdContext = createContext<PretextMdConfig>(defaultConfig)

export function usePretextMdConfig(): PretextMdConfig {
  return useContext(PretextMdContext)
}

'use client'

import React, { useMemo, memo, useState, useRef, useEffect, useLayoutEffect, createContext, useContext } from 'react'
import { parse } from '../core/parser'
import { measureBlocks } from '../core/block-layout'
import type {
  BlockNode,
  ListNode,
  TableNode,
  InlineItem,
  MeasuredBlock,
  MeasuredLine,
  LineFragment,
  MeasureConfig,
  HeadingNode,
  ImageNode,
  CodeBlockNode,
  EmbedPlugin,
} from '../core/types'
import { usePretextMdConfig } from './context'
import {
  defaultPlugins,
  renderCodeBlock,
  renderYouTube,
  renderImage,
  renderTable,
} from './plugins'
import { CodeBlock } from '@/components/infsh/code-block/code-block'

const DEFAULT_PLUGINS = defaultPlugins()

// --- Plugin render registry ---
// Maps plugin name → render function. Plugins own both measure and render.
// Receives MeasuredBlock so container plugins can render measured children.

type PluginRenderer = (block: MeasuredBlock, renderChild: (b: MeasuredBlock) => React.ReactNode) => React.ReactNode

const defaultRenderers: Record<string, PluginRenderer> = {
  'code-block': (b) => renderCodeBlock(b.node as CodeBlockNode),
  'blockquote': (b, renderChild) => (
    <blockquote className="border-l-2 border-muted-foreground/30 pl-4">
      {b.children?.map((child, i) => <React.Fragment key={i}>{renderChild(child)}</React.Fragment>)}
    </blockquote>
  ),
  'list': (b) => {
    const node = b.node as ListNode
    const Tag = node.ordered ? 'ol' : 'ul'
    return (
      <Tag className={node.ordered ? 'list-decimal pl-6' : 'list-disc pl-6'} start={node.start}>
        {b.items?.map((measuredBlocks, i) => (
          <li key={i}>
            {measuredBlocks.map((child, j) => (
              <MeasuredBlockRenderer key={j} block={child} />
            ))}
          </li>
        ))}
      </Tag>
    )
  },
  'youtube': (b) => renderYouTube(b.node as ImageNode),
  'image': (b) => renderImage(b.node as ImageNode),
  'table': (b) => renderTable(b.node as TableNode),
  'hr': () => <hr className="border-border" />,
}

// --- Plugin context ---

const PluginsContext = createContext<{
  plugins: EmbedPlugin[]
  renderers: Record<string, PluginRenderer>
}>({ plugins: [], renderers: defaultRenderers })

function usePlugins() {
  return useContext(PluginsContext)
}

function findPluginForNode(
  node: BlockNode,
  plugins: EmbedPlugin[],
): EmbedPlugin | null {
  for (const p of plugins) {
    if (p.match(node)) return p
  }
  return null
}

// --- Main component ---

type MarkdownProps = {
  content: string
  /** Fixed width for measurement. If omitted, auto-measures container width. */
  maxWidth?: number
  className?: string
  measured?: boolean
  plugins?: EmbedPlugin[]
  renderers?: Record<string, PluginRenderer>
}

export const Markdown = memo(function Markdown({
  content,
  maxWidth: maxWidthProp,
  className,
  measured = true,
  plugins: userPlugins,
  renderers: userRenderers,
}: MarkdownProps) {
  const config = usePretextMdConfig()
  const plugins = userPlugins ?? DEFAULT_PLUGINS
  const renderers = useMemo(
    () => ({ ...defaultRenderers, ...userRenderers }),
    [userRenderers],
  )

  // Auto-measure container width when maxWidth not provided
  const containerRef = useRef<HTMLDivElement>(null)
  const [containerWidth, setContainerWidth] = useState(0)

  // Sync read on mount — get width before first paint (no flow-mode flash)
  useLayoutEffect(() => {
    if (maxWidthProp !== undefined) return
    const el = containerRef.current
    if (el) {
      const w = Math.floor(el.getBoundingClientRect().width)
      if (w > 0) setContainerWidth(w)
    }
  }, [maxWidthProp])

  // RO for subsequent resize updates
  useEffect(() => {
    if (maxWidthProp !== undefined) return
    const el = containerRef.current
    if (!el || typeof ResizeObserver === 'undefined') return
    const ro = new ResizeObserver(([entry]) => {
      if (entry) {
        const w = Math.floor(entry.contentRect.width)
        setContainerWidth(prev => Math.abs(prev - w) > 1 ? w : prev)
      }
    })
    ro.observe(el)
    return () => ro.disconnect()
  }, [maxWidthProp])

  const maxWidth = maxWidthProp ?? containerWidth

  const data = useMemo(() => {
    if (!content) return null
    const blocks = parse(content)
    if (!measured || maxWidth <= 0) return { blocks, result: null }
    const measureConfig: MeasureConfig = {
      maxWidth,
      fonts: config.fonts,
      lineHeights: config.lineHeights,
      plugins,
    }
    return { blocks, result: measureBlocks(blocks, measureConfig) }
  }, [content, maxWidth, config.fonts, config.lineHeights, measured, plugins])

  if (!data) return null

  const ctx = { plugins, renderers }

  if (!data.result) {
    return (
      <PluginsContext.Provider value={ctx}>
        <div ref={containerRef} className={className} style={{ display: 'flex', flexDirection: 'column', gap: 12, width: maxWidthProp === undefined ? '100%' : undefined }}>
          {data.blocks.map((block, i) => (
            <FlowBlockRenderer key={i} node={block} />
          ))}
        </div>
      </PluginsContext.Provider>
    )
  }

  return (
    <PluginsContext.Provider value={ctx}>
      <div ref={containerRef} className={className} style={{ display: 'flex', flexDirection: 'column', gap: 12, width: maxWidthProp === undefined ? '100%' : undefined }}>
        {data.result.blocks.map((block, i) => (
          <MeasuredBlockRenderer key={i} block={block} />
        ))}
      </div>
    </PluginsContext.Provider>
  )
})

// ============================================================
// MEASURED MODE
// ============================================================

function MeasuredBlockRenderer({ block }: { block: MeasuredBlock }) {
  const { plugins, renderers } = usePlugins()
  const node = block.node

  // Plugin-rendered blocks
  const plugin = findPluginForNode(node, plugins)
  if (plugin) {
    const render = renderers[plugin.name]
    if (render) return <>{render(block, (child) => <MeasuredBlockRenderer block={child} />)}</>
  }

  // Core inline block types
  switch (node.kind) {
    case 'paragraph':
      return <MeasuredInlineBlock block={block} tag="p" />
    case 'heading':
      return <MeasuredInlineBlock block={block} tag={`h${node.level}`} />
    default:
      return null
  }
}

function MeasuredInlineBlock({ block, tag }: { block: MeasuredBlock; tag: string }) {
  if (!block.lines) return null
  const Tag = tag as any
  const lh = block.lines.length > 0 ? block.height / block.lines.length : 20
  return (
    <Tag style={{ margin: 0, width: '100%' }}>
      {block.lines.map((line, i) => (
        <MeasuredLineRenderer key={i} line={line} lineHeight={lh} />
      ))}
    </Tag>
  )
}


function MeasuredLineRenderer({ line, lineHeight }: { line: MeasuredLine; lineHeight: number }) {
  return (
    <span style={{ display: 'block', height: lineHeight, whiteSpace: 'nowrap' }}>
      {line.fragments.map((frag, i) => (
        <FragmentRenderer key={i} fragment={frag} />
      ))}
    </span>
  )
}

function FragmentRenderer({ fragment }: { fragment: LineFragment }) {
  const style: React.CSSProperties = { font: fragment.font }
  const space = fragment.leadingGap > 0 ? ' ' : ''

  if (fragment.isCode) {
    return (
      <>{space}<code
        className="bg-foreground/[0.06] rounded px-1 py-0.5"
        style={style}
      >{fragment.text}</code></>
    )
  }

  let content: React.ReactNode = fragment.text
  if (fragment.isStrikethrough) content = <del>{content}</del>
  if (fragment.href) {
    return <>{space}<a href={fragment.href} className="underline text-primary" style={style}>{content}</a></>
  }
  return <>{space}<span style={style}>{content}</span></>
}


// ============================================================
// FLOW MODE — normal browser layout, same parsed AST
// ============================================================

function FlowBlockRenderer({ node }: { node: BlockNode }) {
  const { plugins, renderers } = usePlugins()

  // Leaf plugins (code-block, youtube, image, hr) work in flow mode too
  const plugin = findPluginForNode(node, plugins)
  if (plugin && !plugin.measureBlock) {
    const render = renderers[plugin.name]
    if (render) return <>{render({ node, height: 0, y: 0 }, () => null)}</>
  }

  switch (node.kind) {
    case 'paragraph':
      return <p className="text-sm leading-5"><FlowInlineItems items={node.items} /></p>
    case 'heading':
      return <FlowHeading node={node} />
    case 'code-block':
      return <FlowCodeBlock node={node as CodeBlockNode} />
    case 'blockquote':
      return (
        <blockquote className="border-l-2 border-muted-foreground/30 pl-4">
          {node.children.map((child, i) => (
            <FlowBlockRenderer key={i} node={child} />
          ))}
        </blockquote>
      )
    case 'list': {
      const Tag = node.ordered ? 'ol' : 'ul'
      return (
        <Tag className={`${node.ordered ? 'list-decimal' : 'list-disc'} pl-6 text-sm leading-5`} start={node.start}>
          {node.items.map((itemBlocks, i) => (
            <li key={i}>
              {itemBlocks.map((child, j) => (
                <FlowBlockRenderer key={j} node={child} />
              ))}
            </li>
          ))}
        </Tag>
      )
    }
    default:
      return null
  }
}

function FlowHeading({ node }: { node: HeadingNode }) {
  const Tag = `h${node.level}` as const
  const sizes: Record<number, string> = {
    1: 'text-2xl font-bold',
    2: 'text-xl font-bold',
    3: 'text-base font-bold',
    4: 'text-sm font-bold',
    5: 'text-sm font-bold',
    6: 'text-xs font-bold',
  }
  return (
    <Tag className={sizes[node.level]}>
      <FlowInlineItems items={node.items} />
    </Tag>
  )
}

function FlowCodeBlock({ node }: { node: CodeBlockNode }) {
  return (
    <CodeBlock language={node.lang} showHeader={!!node.lang} showLineNumbers={false} className="!my-0 !h-auto">
      {node.code}
    </CodeBlock>
  )
}

function FlowInlineItems({ items }: { items: InlineItem[] }) {
  return (
    <>
      {items.map((item, i) => (
        <FlowInlineItem key={i} item={item} />
      ))}
    </>
  )
}

function FlowInlineItem({ item }: { item: InlineItem }) {
  switch (item.kind) {
    case 'text': {
      const Tag = item.font === 'bold' || item.font === 'boldItalic' ? 'strong' : item.font === 'italic' ? 'em' : item.font === 'strikethrough' ? 'del' : 'span'
      if (item.font === 'boldItalic') return <strong><em>{item.text}</em></strong>
      return <Tag>{item.text}</Tag>
    }
    case 'code':
      return <code className="bg-foreground/[0.06] rounded px-1 py-0.5 text-[0.9em]">{item.text}</code>
    case 'link':
      return (
        <a href={item.href} className="underline text-primary">
          <FlowInlineItems items={item.items} />
        </a>
      )
    case 'break':
      return <br />
    default:
      return null
  }
}

'use client'

import React from 'react'
import type {
  BlockNode,
  BlockquoteNode,
  ListNode,
  CodeBlockNode,
  ImageNode,
  TableNode,
  EmbedPlugin,
  PluginContext,
} from '../core/types'
import { splitLines } from '@/components/infsh/code-block/utils'
import { CodeBlock } from '@/components/infsh/code-block/code-block'
import { YouTubeEmbed } from '@/components/infsh/youtube-embed'
import ZoomableImage from '@/components/infsh/zoomable-image'

// --- YouTube detection ---

function getYouTubeVideoId(url: string): string | null {
  const m = url.match(/(?:youtu\.be\/|youtube\.com\/(?:embed\/|v\/|watch\?v=|shorts\/))([a-zA-Z0-9_-]{11})/)
  return m?.[1] ?? null
}

// --- Code block plugin ---
// Owns its own chrome dimensions — core doesn't know about these.

const CODE_BLOCK_CHROME = {
  headerHeight: 33,  // py-2 (16px) + text-xs line (16px) + border-b (1px)
  paddingY: 32,      // p-4 top + bottom
  border: 2,         // border top + bottom
} as const

export function codeBlockPlugin(lineHeight: number = 18): EmbedPlugin {
  return {
    name: 'code-block',
    match: (node) => node.kind === 'code-block',
    measure: (node) => {
      const codeNode = node as CodeBlockNode
      const hasHeader = !!codeNode.lang
      const numLines = splitLines(codeNode.code).length
      const height =
        (hasHeader ? CODE_BLOCK_CHROME.headerHeight : 0) +
        CODE_BLOCK_CHROME.paddingY +
        numLines * lineHeight +
        CODE_BLOCK_CHROME.border
      return { kind: 'computed', height }
    },
  }
}

export function renderCodeBlock(node: CodeBlockNode): React.ReactNode {
  return (
    <CodeBlock language={node.lang} showHeader={!!node.lang} showLineNumbers={false} className="!my-0 !h-auto">
      {node.code}
    </CodeBlock>
  )
}

// --- YouTube plugin ---

export function youtubePlugin(): EmbedPlugin {
  return {
    name: 'youtube',
    match: (node) =>
      node.kind === 'image' && getYouTubeVideoId((node as ImageNode).src) !== null,
    measure: () => ({ kind: 'aspect-ratio', ratio: 16 / 9 }),
  }
}

export function renderYouTube(node: ImageNode): React.ReactNode {
  const videoId = getYouTubeVideoId(node.src)!
  return <YouTubeEmbed videoId={videoId} title={node.alt} />
}

// --- Image plugin ---

export function imagePlugin(): EmbedPlugin {
  return {
    name: 'image',
    match: (node) => node.kind === 'image',
    measure: (_, maxWidth) => ({ kind: 'aspect-ratio', ratio: 16 / 9, maxHeight: 400 }),
  }
}

export function renderImage(node: ImageNode): React.ReactNode {
  return <ZoomableImage src={node.src} alt={node.alt} className="rounded-md max-w-full" />
}

// --- HR plugin ---

export function hrPlugin(): EmbedPlugin {
  return {
    name: 'hr',
    match: (node) => node.kind === 'hr',
    measure: () => ({ kind: 'fixed', height: 1 }),
  }
}

// --- Blockquote plugin ---

export function blockquotePlugin(indent: number = 20): EmbedPlugin {
  return {
    name: 'blockquote',
    match: (node) => node.kind === 'blockquote',
    measure: () => ({ kind: 'fixed', height: 0 }), // unused — measureBlock handles it
    measureBlock: (node: BlockquoteNode, ctx) => {
      const innerConfig = { ...ctx.config, maxWidth: ctx.config.maxWidth - indent }
      const inner = ctx.measureBlocks(node.children, innerConfig)
      return { node, height: inner.height, y: 0, children: inner.blocks }
    },
  }
}

// --- List plugin ---

export function listPlugin(indent: number = 24): EmbedPlugin {
  return {
    name: 'list',
    match: (node) => node.kind === 'list',
    measure: () => ({ kind: 'fixed', height: 0 }), // unused — measureBlock handles it
    measureBlock: (node: ListNode, ctx) => {
      const innerConfig = { ...ctx.config, maxWidth: ctx.config.maxWidth - indent }
      let totalHeight = 0
      const measuredItems = node.items.map(itemBlocks => {
        const inner = ctx.measureBlocks(itemBlocks, innerConfig)
        totalHeight += inner.height
        return inner.blocks
      })
      return { node, height: totalHeight, y: 0, items: measuredItems }
    },
  }
}

// --- Table plugin ---

const TABLE_ROW_HEIGHT = 33 // px-3 py-1.5 (12px) + text-sm line (~16px) + border (1px) + padding
const TABLE_HEADER_HEIGHT = 33

export function tablePlugin(): EmbedPlugin {
  return {
    name: 'table',
    match: (node) => node.kind === 'table',
    measure: (node) => {
      const table = node as TableNode
      const height = TABLE_HEADER_HEIGHT + (table.rows.length - 1) * TABLE_ROW_HEIGHT + 2 // 2 = border
      return { kind: 'computed', height }
    },
  }
}

export function renderTable(node: TableNode): React.ReactNode {
  if (node.rows.length === 0) return null
  const [headerRow, ...bodyRows] = node.rows
  const align = node.align

  return (
    <div className="min-w-0 overflow-x-auto border border-border rounded-md">
      <table className="w-full">
        {headerRow && (
          <thead className="border-b border-border">
            <tr>
              {headerRow.map((cell, i) => (
                <th
                  key={i}
                  className="px-3 py-1.5 text-left text-xs text-muted-foreground"
                  style={align[i] ? { textAlign: align[i]! } : undefined}
                >
                  <FlowCellInlines items={cell} />
                </th>
              ))}
            </tr>
          </thead>
        )}
        <tbody>
          {bodyRows.map((row, ri) => (
            <tr key={ri} className="border-b border-border last:border-0">
              {row.map((cell, ci) => (
                <td
                  key={ci}
                  className="px-3 py-1.5 text-sm"
                  style={align[ci] ? { textAlign: align[ci]! } : undefined}
                >
                  <FlowCellInlines items={cell} />
                </td>
              ))}
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  )
}

/** Render inline items inside a table cell — reuses the same inline rendering as flow mode. */
function FlowCellInlines({ items }: { items: import('../core/types').InlineItem[] }) {
  return (
    <>
      {items.map((item, i) => {
        switch (item.kind) {
          case 'text': {
            const Tag = item.font === 'bold' || item.font === 'boldItalic' ? 'strong' : item.font === 'italic' ? 'em' : item.font === 'strikethrough' ? 'del' : 'span'
            if (item.font === 'boldItalic') return <strong key={i}><em>{item.text}</em></strong>
            return <Tag key={i}>{item.text}</Tag>
          }
          case 'code':
            return <code key={i} className="bg-foreground/[0.06] rounded px-1 py-0.5 text-[0.9em]">{item.text}</code>
          case 'link':
            return <a key={i} href={item.href} className="underline text-primary"><FlowCellInlines items={item.items} /></a>
          case 'break':
            return <br key={i} />
          default:
            return null
        }
      })}
    </>
  )
}

// --- Default plugin set ---

export function defaultPlugins(): EmbedPlugin[] {
  return [codeBlockPlugin(), blockquotePlugin(), listPlugin(), youtubePlugin(), imagePlugin(), hrPlugin(), tablePlugin()]
}
